@patch
def view(self:Notebook, id, nums=True):
    "Show cell source with optional line numbers"
    lines = self[id].source.splitlines()
    if nums: lines = [f'{i+1:6d} │ {l}' for i,l in enumerate(lines)]
    return '\n'.join(lines)
